package main

import (
	"encoding/gob"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"sync"
	"time"
)

type Session struct {
	UserID       string
	Preferences  map[string]interface{}
	Permissions  []string
	CreatedAt    time.Time
	LastAccessed time.Time
}

type SessionManager struct {
	sessions map[string]*Session
	mu       sync.RWMutex
	dir      string
}

func NewSessionManager(dir string) (*SessionManager, error) {
	if err := os.MkdirAll(dir, 0755); err != nil {
		return nil, err
	}
	
	sm := &SessionManager{
		sessions: make(map[string]*Session),
		dir:      dir,
	}
	
	sm.loadAllSessions()
	return sm, nil
}

func (sm *SessionManager) CreateSession(userID string, preferences map[string]interface{}, permissions []string) (*Session, error) {
	session := &Session{
		UserID:       userID,
		Preferences:  preferences,
		Permissions:  permissions,
		CreatedAt:    time.Now(),
		LastAccessed: time.Now(),
	}
	
	sm.mu.Lock()
	sm.sessions[userID] = session
	sm.mu.Unlock()
	
	return session, sm.saveSession(session)
}

func (sm *SessionManager) GetSession(userID string) (*Session, bool) {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	
	session, exists := sm.sessions[userID]
	if !exists {
		return nil, false
	}
	
	session.LastAccessed = time.Now()
	return session, true
}

func (sm *SessionManager) DeleteSession(userID string) error {
	sm.mu.Lock()
	delete(sm.sessions, userID)
	sm.mu.Unlock()
	
	return sm.deleteSessionFile(userID)
}

func (sm *SessionManager) saveSession(session *Session) error {
	filePath := filepath.Join(sm.dir, fmt.Sprintf("%s.session", session.UserID))
	
	file, err := os.Create(filePath)
	if err != nil {
		return err
	}
	defer file.Close()
	
	encoder := gob.NewEncoder(file)
	encoder.SetEscapeHTML(false)
	return encoder.Encode(session)
}

func (sm *SessionManager) loadSession(userID string) (*Session, error) {
	filePath := filepath.Join(sm.dir, fmt.Sprintf("%s.session", userID))
	
	file, err := os.Open(filePath)
	if err != nil {
		return nil, err
	}
	defer file.Close()
	
	var session Session
	decoder := gob.NewDecoder(file)
	err = decoder.Decode(&session)
	if err != nil {
		return nil, err
	}
	
	return &session, nil
}

func (sm *SessionManager) loadAllSessions() {
	files, err := os.ReadDir(sm.dir)
	if err != nil {
		return
	}
	
	for _, file := range files {
		if filepath.Ext(file.Name()) == ".session" {
			userID := strings.TrimSuffix(file.Name(), ".session")
			if session, err := sm.loadSession(userID); err == nil {
				sm.mu.Lock()
				sm.sessions[userID] = session
				sm.mu.Unlock()
			}
		}
	}
}

func (sm *SessionManager) deleteSessionFile(userID string) error {
	filePath := filepath.Join(sm.dir, fmt.Sprintf("%s.session", userID))
	return os.Remove(filePath)
}

func (sm *SessionManager) UpdatePreferences(userID string, preferences map[string]interface{}) error {
	session, exists := sm.GetSession(userID)
	if !exists {
		return fmt.Errorf("session not found")
	}
	
	for key, value := range preferences {
		session.Preferences[key] = value
	}
	
	session.LastAccessed = time.Now()
	return sm.saveSession(session)
}

func (sm *SessionManager) AddPermission(userID string, permission string) error {
	session, exists := sm.GetSession(userID)
	if !exists {
		return fmt.Errorf("session not found")
	}
	
	for _, perm := range session.Permissions {
		if perm == permission {
			return nil
		}
	}
	
	session.Permissions = append(session.Permissions, permission)
	session.LastAccessed = time.Now()
	return sm.saveSession(session)
}

func (sm *SessionManager) GetSessions() map[string]*Session {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	
	sessions := make(map[string]*Session)
	for k, v := range sm.sessions {
		sessions[k] = v
	}
	
	return sessions
}

func (sm *SessionManager) Close() error {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	for userID, session := range sm.sessions {
		if err := sm.saveSession(session); err != nil {
			return err
		}
		delete(sm.sessions, userID)
	}
	
	return nil
}